//! Metal inference engine — decode loop for Apple Silicon.
//! @section Inference Runtime
//! This is the Metal equivalent of forward.zig (Vulkan).
//! Uses MSL compute shaders dispatched via the Metal shim.
const std = @import("std");
const config_mod = @import("../model/config.zig");
const ModelConfig = config_mod.ModelConfig;
const gguf = @import("../model/gguf.zig");
const memory_plan = @import("../gpu/memory_plan.zig");
const metal_loader = @import("../model/loader_metal.zig");
const runtime_assets = @import("../runtime_assets.zig");
const metal_device = @import("../metal/device.zig");
const metal_buffer = @import("../metal/buffer.zig");
const MetalBuffer = metal_buffer.MetalBuffer;
const metal_pipeline = @import("../metal/pipeline.zig");
const MetalPipeline = metal_pipeline.MetalPipeline;
const metal_command = @import("../metal/command.zig");
const MetalCommand = metal_command.MetalCommand;
/// Command-encoder mode re-export used by runtime init options.
pub const CommandEncoderMode = metal_command.CommandEncoderMode;
const kernel_timing = @import("../metal/kernel_timing.zig");
const shim = @import("../metal/c.zig").shim;

const log = std.log.scoped(.forward);
/// Upper bound on the Metal KV-cache allocation: we still honour the model's
/// architectural context length and the unified-memory budget, but we refuse
/// to allocate more tokens than this in one block to keep allocation latency
/// and staging buffers sane. Callers that already right-sized `cfg.context_length`
/// from the device budget (see `memory_plan.autoContextTokensForDeviceBudget`)
/// see this as a soft safety net rather than the primary limit.
pub const runtime_context_cap: u32 = 262144;
const queued_prefill_embed_tokens: usize = 256;
const qwen_ssm_projection_prefill_max_tokens: u32 = 256;
const qwen_ssm_projection_prefill_min_tokens: usize = 32;
const qwen_ssm_projection_validate_tokens: u32 = 4;
// llama.cpp's Metal `ggml_metal_op_mul_mat_id` switches from the small
// matrix-vector path to the expert-grouped matrix path at 32 prompt rows, but
// that is only the minimum batch shape. Validate Qwen route packing closer to
// the Effort 16 prompt so vLLM-style expert block packing and the SSM prefix
// validator exercise about 1K route slots by default.
const qwen_moe_route_pack_validate_tokens: u32 = 128;
// Let the Qwen3.6 llama.cpp-style graph batching / vLLM route-packed MoE
// prefix run until the model ends or a per-layer support guard fails. This
// keeps the layer-major prompt path from falling back to token-major decode at
// an arbitrary layer cap.
const qwen_route_packed_prefix_layer_limit: usize = std.math.maxInt(usize);
const moe_route_block_cols: u32 = 8;
const moe_cols_dense_dispatch_cols: u32 = 4;

/// Runtime state for the decode loop.
pub const DecodeState = struct {
    position: u32,
    generated_tokens: std.ArrayList(u32),
    requested_context_tokens: u32,
    allocator: std.mem.Allocator,

    /// Initialize decode state for a fresh Metal generation request.
    pub fn init(allocator: std.mem.Allocator) DecodeState {
        return .{
            .position = 0,
            .generated_tokens = .{},
            .requested_context_tokens = 0,
            .allocator = allocator,
        };
    }

    /// Release the generated-token buffer owned by this decode state.
    pub fn deinit(self: *DecodeState) void {
        self.generated_tokens.deinit(self.allocator);
        self.* = undefined;
    }
};

/// Metrics from generateWithMetrics: prefill/decode token counts, timing, and throughput.
pub const GenerateMetrics = struct {
    prefill_tokens: usize,
    prefill_ns: u64,
    prefill_tps: f64,
    generated_tokens: u32,
    decode_ns: u64,
    decode_tps: f64,
    ms_per_token: f64,
    eos_at_first_position: bool,
};

/// Output tokens and performance metrics from a generation run.
pub const GenerateResult = struct {
    output_tokens: []u32,
    metrics: GenerateMetrics,

    /// Free the generated token slice returned by `generateWithMetrics`.
    pub fn deinit(self: *GenerateResult, allocator: std.mem.Allocator) void {
        allocator.free(self.output_tokens);
        self.* = undefined;
    }
};

/// Token sampling parameters: temperature, top-k, top-p, and repetition penalty.
pub const SamplingParams = struct {
    temperature: f32 = 0.0,
    top_p: f32 = 1.0,
    repetition_penalty: f32 = 1.0,
    top_k: u32 = 64,

    /// Return whether sampling settings require CPU-visible logits instead of greedy argmax.
    pub fn requiresLogitsReadback(self: @This()) bool {
        return self.temperature > 0.0001 or self.top_p < 0.9999 or self.repetition_penalty > 1.0001;
    }
};

/// Options for `InferenceEngine.init`: profiling, debug validation, KV cache, and dispatch tuning.
pub const InitOptions = struct {
    profile_enabled: bool = false,
    debug_validation_enabled: bool = false,
    q8_tg_override: ?u32 = null,
    q8_dual_tg_override: ?u32 = null,
    kv_cache_q8_override: ?bool = null,
    private_decode_buffers_override: ?bool = null,
    command_encoder_mode: ?CommandEncoderMode = null,
};

fn tensorBytes(model: *const metal_loader.Model) u64 {
    return metal_loader.residentWeightBytes(model);
}

fn memoryBudget(device: *const metal_device.MetalDevice) u64 {
    const working_set = device.recommendedMaxWorkingSetSize();
    if (working_set > 0) return working_set;
    return device.totalMemory();
}

fn memoryPlanningBudget(device: *const metal_device.MetalDevice) u64 {
    return @divTrunc(memoryBudget(device) * 85, 100);
}

fn tokenSeen(history: []const u32, token: u32) bool {
    for (history) |t| {
        if (t == token) return true;
    }
    return false;
}

fn adjustedLogit(logit: f32, token: u32, history: []const u32, repetition_penalty: f32) f32 {
    if (repetition_penalty <= 1.0001 or !tokenSeen(history, token)) return logit;
    if (logit >= 0) return logit / repetition_penalty;
    return logit * repetition_penalty;
}

fn softcapLogit(logit: f32, softcap: f32) f32 {
    if (!(softcap > 0)) return logit;
    return softcap * std.math.tanh(logit / softcap);
}

fn sampleFromLogits(logits: []const f32, history: []const u32, params: SamplingParams, random: std.Random, final_logit_softcapping: f32) u32 {
    if (logits.len == 0) return 0;
    if (params.temperature <= 0.0001) {
        var best_idx: u32 = 0;
        var best_val = adjustedLogit(softcapLogit(logits[0], final_logit_softcapping), 0, history, params.repetition_penalty);
        for (logits[1..], 1..) |raw, i| {
            const val = adjustedLogit(softcapLogit(raw, final_logit_softcapping), @intCast(i), history, params.repetition_penalty);
            if (val > best_val) {
                best_val = val;
                best_idx = @intCast(i);
            }
        }
        return best_idx;
    }

    const max_candidates = 128;
    const top_k: usize = @min(@max(params.top_k, 1), max_candidates);
    const temperature = @max(params.temperature, 0.0001);
    var candidate_ids: [max_candidates]u32 = undefined;
    var candidate_logits: [max_candidates]f32 = undefined;
    var candidate_count: usize = 0;

    for (logits, 0..) |raw_val, i| {
        if (!std.math.isFinite(raw_val)) continue;
        const val = adjustedLogit(softcapLogit(raw_val, final_logit_softcapping), @intCast(i), history, params.repetition_penalty);
        var insert_at = candidate_count;
        while (insert_at > 0 and val > candidate_logits[insert_at - 1]) : (insert_at -= 1) {}
        if (insert_at >= top_k) continue;
        if (candidate_count < top_k) candidate_count += 1;
        var j = candidate_count - 1;
        while (j > insert_at) : (j -= 1) {
            candidate_ids[j] = candidate_ids[j - 1];
            candidate_logits[j] = candidate_logits[j - 1];
        }
        candidate_ids[insert_at] = @intCast(i);
        candidate_logits[insert_at] = val;
    }

    if (candidate_count <= 1) return if (candidate_count == 1) candidate_ids[0] else 0;

    var weights: [max_candidates]f64 = undefined;
    const max_logit = @as(f64, candidate_logits[0]) / @as(f64, temperature);
    var total_weight: f64 = 0.0;
    for (0..candidate_count) |i| {
        const weight = @exp(@as(f64, candidate_logits[i]) / @as(f64, temperature) - max_logit);
        weights[i] = weight;
        total_weight += weight;
    }
    if (!(total_weight > 0.0) or !std.math.isFinite(total_weight)) return candidate_ids[0];

    const safe_top_p = std.math.clamp(params.top_p, 0.0, 1.0);
    var keep_count = candidate_count;
    if (safe_top_p < 0.9999) {
        var cumulative: f64 = 0.0;
        for (0..candidate_count) |i| {
            cumulative += weights[i] / total_weight;
            keep_count = i + 1;
            if (cumulative >= @as(f64, safe_top_p) and i > 0) break;
        }
    }

    var kept_weight: f64 = 0.0;
    for (0..keep_count) |i| kept_weight += weights[i];
    if (!(kept_weight > 0.0)) return candidate_ids[0];

    const target = random.float(f64) * kept_weight;
    var cumulative: f64 = 0.0;
    for (0..keep_count) |i| {
        cumulative += weights[i];
        if (target <= cumulative) return candidate_ids[i];
    }
    return candidate_ids[keep_count - 1];
}

fn readThreadgroupOverride(env_name: [:0]const u8, simd_width: u32, max_threads: u32) ?u32 {
    const raw = std.posix.getenv(env_name) orelse return null;
    if (simd_width == 0 or max_threads == 0) return null;

    const value = std.fmt.parseUnsigned(u32, raw, 10) catch return null;
    if (value == 0 or value > max_threads or value % simd_width != 0) return null;
    return value;
}

fn defaultQ8Threadgroup(chip: metal_device.GpuFamily, simd_width: u32, max_threads: u32) ?u32 {
    if (simd_width == 0 or max_threads < 512) return null;
    if (chip == .apple9 and simd_width == 32) return 512;
    return null;
}

fn defaultQ8DualThreadgroup(chip: metal_device.GpuFamily, simd_width: u32, max_threads: u32) ?u32 {
    if (simd_width == 0 or max_threads < 512) return null;
    if (chip == .apple9 and simd_width == 32) return 512;
    return null;
}

fn preferApple9Q8K2048Path(tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    if (K > 2048) return false;

    const name = tensor.info.name;
    if (std.mem.endsWith(u8, name, "ffn_gate_shexp.weight")) {
        return M <= 512 and K == 2048;
    }
    if (std.mem.endsWith(u8, name, "ffn_down_shexp.weight")) {
        return M <= 2048 and K <= 512;
    }
    return false;
}

fn preferApple9QwenSharedDownQ8QuadShape(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    return cfg.architecture == .qwen2_moe and
        cfg.hidden_dim == 2048 and
        cfg.ssm_d_inner == 4096 and
        cfg.n_experts == 256 and
        cfg.n_experts_used == 8 and
        M == 2048 and
        K == 512 and
        std.mem.endsWith(u8, tensor.info.name, "ffn_down_shexp.weight");
}

fn preferApple9QwenSsmQ8QuadShape(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    return cfg.architecture == .qwen2_moe and
        cfg.hidden_dim == 2048 and
        cfg.ssm_d_inner == 4096 and
        cfg.n_experts == 256 and
        cfg.n_experts_used == 8 and
        K == 2048 and
        M >= 4096 and
        (std.mem.endsWith(u8, tensor.info.name, "attn_qkv.weight") or
            std.mem.endsWith(u8, tensor.info.name, "attn_gate.weight"));
}

fn preferApple9QwenSsmOutQ8K4096Shape(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    return cfg.architecture == .qwen2_moe and
        cfg.hidden_dim == 2048 and
        cfg.ssm_d_inner == 4096 and
        cfg.n_experts == 256 and
        cfg.n_experts_used == 8 and
        K == 4096 and
        M >= 2048 and
        std.mem.endsWith(u8, tensor.info.name, "ssm_out.weight");
}

fn preferApple9QwenSsmRepackedQ8QuadShape(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    const is_qwen36 = cfg.architecture == .qwen2_moe and
        cfg.hidden_dim == 2048 and
        cfg.ssm_d_inner == 4096 and
        cfg.n_experts == 256 and
        cfg.n_experts_used == 8;
    const is_ssm_shape = is_qwen36 and
        (K == 2048 or K == 4096) and
        M >= 2048 and
        (std.mem.endsWith(u8, tensor.info.name, "attn_qkv.weight") or
            std.mem.endsWith(u8, tensor.info.name, "attn_gate.weight") or
            std.mem.endsWith(u8, tensor.info.name, "ssm_out.weight"));
    const is_full_attn_shape = is_qwen36 and
        ((K == 2048 and M >= 4096 and std.mem.endsWith(u8, tensor.info.name, "attn_q.weight")) or
            (K == 4096 and M == 2048 and std.mem.endsWith(u8, tensor.info.name, "attn_output.weight")));
    if (!is_ssm_shape and !is_full_attn_shape) return false;
    return true;
}

fn preferApple9QwenSsmRepackedQ8QuadPath(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    if (!preferApple9QwenSsmRepackedQ8QuadShape(cfg, tensor, M, K)) return false;
    return readBoolEnv("ZINC_METAL_QWEN_SSM_REPACKED_Q8_QUAD") orelse true;
}

// The Qwen3.6-35B LM head is repacked Q8_0 with M=248320 (vocab) and K=2048.
// The generic nr=2 repacked path loads the activation vector twice per
// simdgroup-pair, while the fixed-K nr=4 `dmmv_q8_0_repacked_k2048_qwen.metal`
// shader reuses the same X load across four adjacent rows, halving the X
// bandwidth share of the per-token LM head matvec (~520 MB at Q8_0).
fn preferApple9LmHeadRepackedQ8K2048Quad(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, lm_head: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    return cfg.architecture == .qwen2_moe and
        tensor == lm_head and
        K == 2048 and
        M >= 65536 and
        M % 4 == 0;
}

fn preferApple9QwenSsmPrivateRepackedQ8(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    if (!preferApple9QwenSsmRepackedQ8QuadPath(cfg, tensor, M, K)) return false;
    return readBoolEnv("ZINC_METAL_QWEN_SSM_REPACKED_Q8_PRIVATE") orelse true;
}

fn preferApple9QwenRouterPrivateRepackedQ8(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    const is_shape = cfg.architecture == .qwen2_moe and
        cfg.hidden_dim == 2048 and
        cfg.ssm_d_inner == 4096 and
        cfg.n_experts == 256 and
        cfg.n_experts_used == 8 and
        M == 256 and
        K == 2048 and
        std.mem.endsWith(u8, tensor.info.name, "ffn_gate_inp.weight");
    if (!is_shape) return false;
    return readBoolEnv("ZINC_METAL_QWEN_ROUTER_REPACKED_Q8_PRIVATE") orelse true;
}

fn preferApple9QwenFullAttnQ8K2048QuadShape(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    return cfg.architecture == .qwen2_moe and
        cfg.hidden_dim == 2048 and
        cfg.ssm_d_inner == 4096 and
        cfg.n_experts == 256 and
        cfg.n_experts_used == 8 and
        K == 2048 and
        M >= 4096 and
        std.mem.endsWith(u8, tensor.info.name, "attn_q.weight");
}

fn preferApple9QwenFullAttnOutQ8K4096Shape(cfg: ModelConfig, tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    return cfg.architecture == .qwen2_moe and
        cfg.hidden_dim == 2048 and
        cfg.ssm_d_inner == 4096 and
        cfg.n_experts == 256 and
        cfg.n_experts_used == 8 and
        M == 2048 and
        K == 4096 and
        std.mem.endsWith(u8, tensor.info.name, "attn_output.weight");
}

fn preferApple9Q8WidePath(tensor: *const metal_loader.LoadedTensor, M: u32, K: u32) bool {
    const name = tensor.info.name;
    if (K <= 2048 and M >= 4096 and
        (std.mem.endsWith(u8, name, "attn_qkv.weight") or
            std.mem.endsWith(u8, name, "attn_gate.weight")))
    {
        return true;
    }
    if (K <= 4096 and M >= 2048 and std.mem.endsWith(u8, name, "ssm_out.weight")) {
        return true;
    }
    return false;
}

fn preferLlamaQ8SmallThreadgroupForQwenSsm(tensor: *const metal_loader.LoadedTensor, M: u32, K: u32, enabled: bool) bool {
    const name = tensor.info.name;

    // Adapt llama.cpp `ggml-metal.metal::kernel_mul_mv_q8_0_f32_impl` and
    // `ggml-metal-impl.h`'s Q8_0 geometry (N_R0=2, N_SG=4): Qwen3.6 SSM
    // prompt prefill is dominated by these Q8 projections, and the 128-thread
    // shape keeps the per-row reduction close to the production Metal backend
    // instead of the wider Apple9 override.
    if (!enabled) return false;

    if (K == 2048 and M >= 4096 and
        std.mem.endsWith(u8, name, "attn_qkv.weight"))
    {
        return true;
    }
    // ssm_out (M=2048, K=4096) and SSM attn_gate (M=4096, K=2048) intentionally
    // fall through to the nr=4 `dmmv_q8_0_repacked_k{2048,4096}_qwen` paths
    // (same llama.cpp adjacent-row matvec grouping that won the cycle-1 LM head
    // route and cycle-4 ssm_out route). The narrower M=4096 attn_gate produces
    // 64 workgroups under nr=4 — between ssm_out's 32 WG and qkv's 128 WG —
    // saturating M4 Max's 40 cores without the qkv-shape over-subscription that
    // regressed in the equivalent attn_qkv (M=8192) experiment.
    return false;
}

fn shouldUseGlobalQ8Override(arch: config_mod.Architecture, tensor_name: []const u8) bool {
    if (arch != .gemma) return true;

    return !(std.mem.endsWith(u8, tensor_name, "ffn_gate.weight") or
        std.mem.endsWith(u8, tensor_name, "ffn_up.weight") or
        std.mem.endsWith(u8, tensor_name, "ffn_down.weight") or
        std.mem.endsWith(u8, tensor_name, "attn_output.weight") or
        std.mem.endsWith(u8, tensor_name, "ffn_gate_shexp.weight") or
        std.mem.endsWith(u8, tensor_name, "ffn_up_shexp.weight") or
        std.mem.endsWith(u8, tensor_name, "ffn_down_shexp.weight"));
}

fn shouldCpuQ8Fallback(arch: config_mod.Architecture, tensor_name: []const u8) bool {
    _ = arch;
    _ = tensor_name;
    return false;
}

fn shouldDebugAttentionValidation(cfg: ModelConfig, position: u32, layer_idx: usize) bool {
    return (cfg.architecture == .gemma and (position == 0 or position == 4 or position == 5) and (layer_idx == 0 or layer_idx == 5 or layer_idx == 17)) or
        (cfg.architecture != .gemma and position == 5 and (layer_idx == 7 or layer_idx == 31));
}

fn readBoolEnv(env_name: [:0]const u8) ?bool {
    const raw = std.posix.getenv(env_name) orelse return null;
    if (std.mem.eql(u8, raw, "1") or std.ascii.eqlIgnoreCase(raw, "true") or std.ascii.eqlIgnoreCase(raw, "yes")) return true;
    if (std.mem.eql(u8, raw, "0") or std.ascii.eqlIgnoreCase(raw, "false") or std.ascii.eqlIgnoreCase(raw, "no")) return false;
    return null;
}

fn readU32Env(env_name: [:0]const u8) ?u32 {
    const raw = std.posix.getenv(env_name) orelse return null;
    return std.fmt.parseUnsigned(u32, raw, 10) catch null;
}

fn qwenMoeRoutePackRequestedValidateTokens() ?u32 {
    return readU32Env("ZINC_QWEN36_35B_PREFILL_VALIDATE_TOKENS") orelse
        readU32Env("ZINC_QWEN36_PREFILL_VALIDATE_TOKENS");
}

fn clampQwenMoeRoutePackValidateTokens(requested: u32) u32 {
    return @min(@max(requested, 1), qwen_ssm_projection_prefill_max_tokens);
}

fn qwenMoeRoutePackValidateTokensForPrompt(prompt_len: usize) u32 {
    const requested = qwenMoeRoutePackRequestedValidateTokens() orelse
        @as(u32, @intCast(@min(prompt_len, @as(usize, qwen_ssm_projection_prefill_max_tokens))));
    return clampQwenMoeRoutePackValidateTokens(requested);
}

fn qwenMoeRoutePackValidateTokens(engine: *const InferenceEngine) u32 {
    const requested = qwenMoeRoutePackRequestedValidateTokens() orelse
        if (engine.qwen_moe_route_validate_target_tokens > 0)
            engine.qwen_moe_route_validate_target_tokens
        else
            qwen_moe_route_pack_validate_tokens;
    return clampQwenMoeRoutePackValidateTokens(requested);
}

fn qwenMoeRoutePackValidateLayer(engine: *const InferenceEngine) usize {
    const requested =
        readU32Env("ZINC_QWEN36_35B_ROUTE_PACK_VALIDATE_LAYER") orelse
        readU32Env("ZINC_QWEN36_ROUTE_PACK_VALIDATE_LAYER") orelse
        engine.qwen_ssm_proj_validate_layer;
    return @intCast(requested);
}

fn qwenRoutePackedPrefixLayerLimit() usize {
    const requested =
        readU32Env("ZINC_QWEN36_35B_ROUTE_PACK_PREFIX_LAYERS") orelse
        readU32Env("ZINC_QWEN36_ROUTE_PACK_PREFIX_LAYERS") orelse
        return qwen_route_packed_prefix_layer_limit;
    return @intCast(@max(requested, 1));
}

fn qwenRoutePackedFullValidationEnabled() bool {
    return (readBoolEnv("ZINC_QWEN36_35B_ROUTE_PACK_VALIDATE_FULL") orelse false) or
        (readBoolEnv("ZINC_QWEN36_ROUTE_PACK_VALIDATE_FULL") orelse false);
}

fn qwenRoutePackedFullValidationBisectEnabled() bool {
    return (readBoolEnv("ZINC_QWEN36_35B_ROUTE_PACK_VALIDATE_FULL_BISECT") orelse false) or
        (readBoolEnv("ZINC_QWEN36_ROUTE_PACK_VALIDATE_FULL_BISECT") orelse false);
}

fn defaultQwen36SsmPrefillProjectionEnabled(cfg: ModelConfig) bool {
    return cfg.architecture == .qwen2_moe and
        cfg.hidden_dim == 2048 and
        cfg.n_layers == 40 and
        cfg.n_experts == 256 and
        cfg.n_experts_used == 8 and
        cfg.ssm_d_inner == 4096 and
        cfg.ssm_d_state == 128 and
        cfg.ssm_dt_rank == 32 and
        cfg.ssm_n_group == 16;
}

fn defaultFusedSsmNormEnabled(cfg: ModelConfig) bool {
    // llama.cpp keeps norm as a separate graph op before the Metal matmul
    // kernels. For the Qwen3.6 35B SSM shape, fusing RMSNorm into per-row Q8
    // DMMV repeats the 2048-wide norm reduction across thousands of rows.
    if (defaultQwen36SsmPrefillProjectionEnabled(cfg)) return false;
    return true;
}

fn fusedSsmDeltaGatedNormEnabled(engine: *const InferenceEngine, head_v_dim: u32, d_state: u32) bool {
    if (!engine.fused_ssm_delta_gated_norm_enabled) return false;
    if (engine.debug_validation_enabled or engine.gemma_moe_validation_enabled or engine.qwen_prefill_validation_enabled) return false;
    if (engine.ssm_delta_net_gated_norm_pipe.handle == null and engine.ssm_delta_net_gated_norm_qwen_pipe.handle == null) return false;
    if (head_v_dim == 0 or head_v_dim > 128 or d_state == 0 or d_state > 128) return false;
    return true;
}

fn canUseQwenSsmDeltaGatedNormExact(
    engine: *const InferenceEngine,
    dt_rank: u32,
    head_v_dim: u32,
    d_state: u32,
    n_group: u32,
    has_dt_bias: bool,
    has_ssm_a: bool,
) bool {
    if (!engine.qwen_ssm_delta_gated_norm_exact_enabled) return false;
    if (!defaultQwen36SsmPrefillProjectionEnabled(engine.config)) return false;
    if (!has_dt_bias or !has_ssm_a) return false;
    if (dt_rank != 32 or head_v_dim != 128 or d_state != 128 or n_group != 16) return false;
    if (engine.ssm_delta_net_gated_norm_qwen_pipe.handle == null) return false;
    return engine.ssm_delta_net_gated_norm_qwen_pipe.thread_execution_width == 32 and
        engine.ssm_delta_net_gated_norm_qwen_pipe.max_threads_per_threadgroup >= 128;
}

fn ssmDeltaGatedNormThreadgroupSize(
    pipe: *const MetalPipeline,
    dt_rank: u32,
    head_v_dim: u32,
    d_state: u32,
    n_group: u32,
) u32 {
    if (dt_rank == 32 and
        head_v_dim == 128 and
        d_state == 128 and
        n_group == 16 and
        pipe.thread_execution_width == 32 and
        pipe.max_threads_per_threadgroup >= 128)
    {
        return 128;
    }
    return 64;
}

fn ssmDeltaNetPrefillThreadgroupSize(
    pipe: *const MetalPipeline,
    dt_rank: u32,
    head_v_dim: u32,
    d_state: u32,
    n_group: u32,
) u32 {
    if (dt_rank == 32 and
        head_v_dim == 128 and
        d_state == 128 and
        n_group == 16 and
        pipe.thread_execution_width == 32 and
        pipe.max_threads_per_threadgroup >= 128)
    {
        return 128;
    }
    return 64;
}

fn canUseQwenSsmConvD4FastPath(
    engine: *const InferenceEngine,
    conv_channels: u32,
    d_conv: u32,
    kernel_is_f16: bool,
) bool {
    return defaultQwen36SsmPrefillProjectionEnabled(engine.config) and
        conv_channels == 8192 and
        d_conv == 4 and
        !kernel_is_f16 and
        engine.ssm_conv1d_qwen_d4_pipe.handle != null;
}

fn qwenSsmConvD4PrefillPipe(
    engine: *const InferenceEngine,
    conv_channels: u32,
    d_conv: u32,
) *const MetalPipeline {
    if (defaultQwen36SsmPrefillProjectionEnabled(engine.config) and
        conv_channels == 8192 and
        d_conv == 4 and
        engine.ssm_conv1d_prefill_qwen_d4_pipe.handle != null)
    {
        return &engine.ssm_conv1d_prefill_qwen_d4_pipe;
    }
    return &engine.ssm_conv1d_prefill_pipe;
}

fn ssmConv1dThreadgroupSize(
    pipe: *const MetalPipeline,
    conv_channels: u32,
    d_conv: u32,
    kernel_is_f16: bool,
) u32 {
    if (conv_channels == 8192 and
        d_conv == 4 and
        !kernel_is_f16 and
        pipe.thread_execution_width == 32 and
        pipe.max_threads_per_threadgroup >= 128)
    {
        return 128;
    }
    return 64;
}

