fn profileStart(enabled: bool) i128 {
    return if (enabled) std.time.nanoTimestamp() else -1;
}

fn profileElapsedNs(start_ns: i128) u64 {
    if (start_ns < 0) return 0;
    const end_ns = std.time.nanoTimestamp();
    if (end_ns <= start_ns) return 0;
    return @intCast(end_ns - start_ns);
}

fn profileBarrier(cmd: *MetalCommand, profile: ?*RuntimeProfile, class: BarrierClass) void {
    const before_count = cmd.barrier_count;
    cmd.barrier();
    if (cmd.barrier_count == before_count) return;
    if (profile) |p| switch (class) {
        .embed => p.embed_barrier_calls += 1,
        .full_attn => p.full_attn_barrier_calls += 1,
        .ssm => p.ssm_barrier_calls += 1,
        .router => p.router_barrier_calls += 1,
        .gpu_routed_moe => p.gpu_routed_moe_barrier_calls += 1,
        .fallback_moe => p.fallback_moe_barrier_calls += 1,
        .dense_ffn => p.dense_ffn_barrier_calls += 1,
        .final => p.final_barrier_calls += 1,
    };
}

fn profileBarrierBuffers(cmd: *MetalCommand, profile: ?*RuntimeProfile, class: BarrierClass, bufs: []const *const MetalBuffer) void {
    const before_count = cmd.barrier_count;
    cmd.barrierBuffers(bufs);
    if (cmd.barrier_count == before_count) return;
    if (profile) |p| switch (class) {
        .embed => p.embed_barrier_calls += 1,
        .full_attn => p.full_attn_barrier_calls += 1,
        .ssm => p.ssm_barrier_calls += 1,
        .router => p.router_barrier_calls += 1,
        .gpu_routed_moe => p.gpu_routed_moe_barrier_calls += 1,
        .fallback_moe => p.fallback_moe_barrier_calls += 1,
        .dense_ffn => p.dense_ffn_barrier_calls += 1,
        .final => p.final_barrier_calls += 1,
    };
}

fn profileResourceBarrierBuffers(cmd: *MetalCommand, profile: ?*RuntimeProfile, class: BarrierClass, bufs: []const *const MetalBuffer) void {
    const before_count = cmd.barrier_count;
    cmd.barrierResourceBuffers(bufs);
    if (cmd.barrier_count == before_count) return;
    if (profile) |p| switch (class) {
        .embed => p.embed_barrier_calls += 1,
        .full_attn => p.full_attn_barrier_calls += 1,
        .ssm => p.ssm_barrier_calls += 1,
        .router => p.router_barrier_calls += 1,
        .gpu_routed_moe => p.gpu_routed_moe_barrier_calls += 1,
        .fallback_moe => p.fallback_moe_barrier_calls += 1,
        .dense_ffn => p.dense_ffn_barrier_calls += 1,
        .final => p.final_barrier_calls += 1,
    };
}

fn recordSsmBarrierPhase(profile: ?*RuntimeProfile, phase: SsmBarrierPhase) void {
    if (profile) |p| {
        p.ssm_barrier_calls += 1;
        switch (phase) {
            .proj_norm => p.ssm_proj_norm_barrier_calls += 1,
            .qkv => p.ssm_qkv_barrier_calls += 1,
            .tail => p.ssm_tail_barrier_calls += 1,
            .conv => p.ssm_conv_barrier_calls += 1,
            .delta => p.ssm_delta_barrier_calls += 1,
            .gated_norm => p.ssm_gated_norm_barrier_calls += 1,
            .out => p.ssm_out_barrier_calls += 1,
            .residual => p.ssm_residual_barrier_calls += 1,
        }
    }
}

fn profileSsmBarrier(cmd: *MetalCommand, profile: ?*RuntimeProfile, phase: SsmBarrierPhase) void {
    const before_count = cmd.barrier_count;
    cmd.barrier();
    if (cmd.barrier_count == before_count) return;
    recordSsmBarrierPhase(profile, phase);
}

fn profileSsmBarrierBuffers(cmd: *MetalCommand, profile: ?*RuntimeProfile, phase: SsmBarrierPhase, bufs: []const *const MetalBuffer) void {
    const before_count = cmd.barrier_count;
    cmd.barrierBuffers(bufs);
    if (cmd.barrier_count == before_count) return;
    recordSsmBarrierPhase(profile, phase);
}

fn profileSsmResourceBarrierBuffers(cmd: *MetalCommand, profile: ?*RuntimeProfile, phase: SsmBarrierPhase, bufs: []const *const MetalBuffer) void {
    const before_count = cmd.barrier_count;
    cmd.barrierResourceBuffers(bufs);
    if (cmd.barrier_count == before_count) return;
    recordSsmBarrierPhase(profile, phase);
}

fn recordGpuMoeBarrierPhase(profile: ?*RuntimeProfile, phase: GpuMoeBarrierPhase) void {
    if (profile) |p| {
        p.gpu_routed_moe_barrier_calls += 1;
        switch (phase) {
            .router => p.gpu_moe_router_barrier_calls += 1,
            .gate_up => p.gpu_moe_gate_up_barrier_calls += 1,
            .activation => p.gpu_moe_activation_barrier_calls += 1,
            .down => p.gpu_moe_down_barrier_calls += 1,
            .finalizer => p.gpu_moe_finalizer_barrier_calls += 1,
        }
    }
}

fn recordGpuMoeFinalizerKind(profile: ?*RuntimeProfile, kind: GpuMoeFinalizerKind) void {
    if (profile) |p| switch (kind) {
        .scalar_seed_norm => p.gpu_moe_finalizer_scalar_seed_norm_calls += 1,
        .scalar => p.gpu_moe_finalizer_scalar_calls += 1,
        .f32_seed_norm => p.gpu_moe_finalizer_f32_seed_norm_calls += 1,
        .f32_norm => p.gpu_moe_finalizer_f32_norm_calls += 1,
        .f32 => p.gpu_moe_finalizer_f32_calls += 1,
        .shared => p.gpu_moe_finalizer_shared_calls += 1,
        .routed_only => p.gpu_moe_finalizer_routed_only_calls += 1,
    };
}

fn profileGpuMoeBarrierBuffers(cmd: *MetalCommand, profile: ?*RuntimeProfile, phase: GpuMoeBarrierPhase, bufs: []const *const MetalBuffer) void {
    const before_count = cmd.barrier_count;
    cmd.barrierBuffers(bufs);
    if (cmd.barrier_count == before_count) return;
    recordGpuMoeBarrierPhase(profile, phase);
}

fn profileFullAttnQkvBarrier(
    cmd: *MetalCommand,
    profile: ?*RuntimeProfile,
    include_q: bool,
    include_k: bool,
    include_v: bool,
    include_gate: bool,
    engine: *const InferenceEngine,
) void {
    var bufs: [4]*const MetalBuffer = undefined;
    var count: usize = 0;
    if (include_q) {
        bufs[count] = &engine.q_buf;
        count += 1;
    }
    if (include_k) {
        bufs[count] = &engine.k_buf;
        count += 1;
    }
    if (include_v) {
        bufs[count] = &engine.v_buf;
        count += 1;
    }
    if (include_gate) {
        bufs[count] = &engine.gate_buf;
        count += 1;
    }
    profileBarrierBuffers(cmd, profile, .full_attn, bufs[0..count]);
}

fn fullAttentionInterval(cfg: ModelConfig) u32 {
    return if (cfg.full_attn_interval > 0) cfg.full_attn_interval else 1;
}

fn isFullAttentionLayer(cfg: ModelConfig, layer_idx: usize) bool {
    return ((@as(u32, @intCast(layer_idx)) + 1) % fullAttentionInterval(cfg)) == 0;
}

fn isSsmLayer(cfg: ModelConfig, layer_idx: usize) bool {
    return cfg.ssm_d_inner > 0 and !isFullAttentionLayer(cfg, layer_idx);
}

/// Return the number of full-attention layers in the model.
pub fn attentionLayerCount(cfg: ModelConfig) u32 {
    const interval = fullAttentionInterval(cfg);
    return if (interval == 0) 0 else @divTrunc(cfg.n_layers, interval);
}

fn kvDim(config: ModelConfig) u32 {
    return config.n_kv_heads * config.head_dim;
}

/// Whether Q8 KV cache quantization should be enabled by default for this model.
pub fn defaultKvCacheQ8Enabled(config: ModelConfig, debug_validation_enabled: bool) bool {
    if (debug_validation_enabled) return false;
    // Disable Q8 KV cache for gpt-oss — the OAI SwiGLU activation is sensitive to
    // quantization noise in the KV cache, causing degenerate output.
    if (config.architecture == .gpt_oss) return false;
    // Gemma4 uses the ISWA attention path in llama.cpp, which applies extra
    // K/V rotation handling when the KV cache is quantized. Metal does not
    // implement that path yet, so keep Gemma4 on the unquantized cache for
    // correctness.
    if (config.architecture == .gemma and config.rope_freq_base_swa > 0) return false;
    const kv_dim = kvDim(config);
    return kv_dim > 0 and config.head_dim > 0 and kv_dim % 32 == 0 and config.head_dim % 32 == 0;
}

/// Bytes consumed per token in the KV cache (depends on Q8 quantization setting).
pub fn kvCacheBytesPerToken(config: ModelConfig, q8_enabled: bool) u64 {
    const kv_dim = @as(u64, kvDim(config));
    if (q8_enabled) {
        return @divTrunc(kv_dim, 32) * 34;
    }
    return kv_dim * @sizeOf(f32);
}

fn nsToMs(ns: u64) f64 {
    return @as(f64, @floatFromInt(ns)) / 1_000_000.0;
}

fn avgMs(ns: u64, count: anytype) f64 {
    const denom = @as(u64, count);
    if (denom == 0) return 0.0;
    return nsToMs(ns) / @as(f64, @floatFromInt(denom));
}

fn pctOf(total_ns: u64, part_ns: u64) f64 {
    if (total_ns == 0) return 0.0;
    return @as(f64, @floatFromInt(part_ns)) * 100.0 / @as(f64, @floatFromInt(total_ns));
}

fn bytesToGiB(bytes: u64) f64 {
    return @as(f64, @floatFromInt(bytes)) / 1_073_741_824.0;
}

fn logDetailedProfileBuckets(label: []const u8, profile: RuntimeProfile) void {
    if (profile.decode_steps == 0 and profile.dmmv_total_bytes == 0) return;

    log.info("  {s} buckets: embed {d:.2} ms | attn proj {d:.2} GiB out {d:.2} GiB flash {d} kv-write {d} | final {d:.2} ms lm-head {d:.2} GiB", .{
        label,
        nsToMs(profile.embedding_ns),
        bytesToGiB(profile.full_attn_projection_bytes),
        bytesToGiB(profile.full_attn_output_bytes),
        profile.full_attn_flash_calls,
        profile.full_attn_kv_write_calls,
        nsToMs(profile.final_record_ns),
        bytesToGiB(profile.lm_head_bytes),
    });
    log.info("  {s} buckets: ssm proj {d:.2} GiB (qkv {d:.2} gate {d:.2} tail {d:.2}) recurrent conv/delta/gated {d}/{d}/{d} out {d:.2} GiB | router {d:.2} GiB topk {d} cpu {d:.2} ms", .{
        label,
        bytesToGiB(profile.ssm_projection_bytes),
        bytesToGiB(profile.ssm_qkv_projection_bytes),
        bytesToGiB(profile.ssm_gate_projection_bytes),
        bytesToGiB(profile.ssm_tail_projection_bytes),
        profile.ssm_conv_calls,
        profile.ssm_delta_calls,
        profile.ssm_gated_norm_calls,
        bytesToGiB(profile.ssm_out_bytes),
        bytesToGiB(profile.router_bytes),
        profile.router_topk_calls,
        nsToMs(profile.router_cpu_ns),
    });
    log.info("  {s} buckets: moe gate/up {d:.2} GiB down {d:.2} GiB | shared gate/up {d:.2} GiB down {d:.2} GiB | waits {d} commits {d:.2} ms", .{
        label,
        bytesToGiB(profile.moe_expert_gate_up_bytes),
        bytesToGiB(profile.moe_expert_down_bytes),
        bytesToGiB(profile.shared_expert_gate_up_bytes),
        bytesToGiB(profile.shared_expert_down_bytes),
        profile.commit_waits,
        nsToMs(profile.gpu_completion_wait_ns),
    });
    log.info("  {s} moe finalizers: scalar+norm {d} scalar {d} f32+seed+norm {d} f32+norm {d} f32 {d} shared {d} routed {d}", .{
        label,
        profile.gpu_moe_finalizer_scalar_seed_norm_calls,
        profile.gpu_moe_finalizer_scalar_calls,
        profile.gpu_moe_finalizer_f32_seed_norm_calls,
        profile.gpu_moe_finalizer_f32_norm_calls,
        profile.gpu_moe_finalizer_f32_calls,
        profile.gpu_moe_finalizer_shared_calls,
        profile.gpu_moe_finalizer_routed_only_calls,
    });
}

fn dmmvPathLabel(path: DmmvPathClass) []const u8 {
    return switch (path) {
        .other => "other",
        .ssm => "ssm",
        .full_attn => "attn",
        .moe_expert => "moe",
        .shared_expert => "shared",
        .router => "router",
        .lm_head => "lm-head",
        .dense_ffn => "dense",
    };
}

/// Push constants for DMMV dispatch (matches GLSL layout).
const DmmvPush = extern struct {
