    /// norm buffers, mirroring the model loader's weight residency set.
    /// `commandBufferWithUnretainedReferences` skips Metal's auto-residency
    /// tracking, so any buffer touched by a recorded dispatch must be
    /// explicitly wired down. Without this the scratch path competes with
    /// the 17.5 GB weight working set and the OS pages it out between
    /// dispatches. Null on macOS < 15 or if creation failed (engine still
    /// runs, just unprotected).
    scratch_rset: ?*shim.MetalRSet = null,

    /// Repack a Q8_0 tensor through a CPU-visible staging buffer, then upload
    /// the coalesced layout into GPU-private storage for hot SSM reads.
    fn createPrivateRepackedQ8Buffer(
        self: *InferenceEngine,
        tensor: *const metal_loader.LoadedTensor,
        size_bytes: usize,
        rows: u32,
        cols: u32,
    ) !MetalBuffer {
        if (size_bytes % @sizeOf(u32) != 0) return error.InvalidQ8RepackSize;

        var staging = try metal_buffer.createBuffer(self.device.ctx, size_bytes);
        defer metal_buffer.freeBuffer(&staging);

        const src_ptr = tensor.gpu_buffer.cpu_ptr orelse return error.MetalBufferNotMapped;
        repackQ8_0Blocks(src_ptr + tensorPageOffset(self.model, tensor), staging.cpu_ptr.?, rows, cols);

        var dst = try metal_buffer.createPrivateBuffer(self.device.ctx, size_bytes);
        errdefer metal_buffer.freeBuffer(&dst);
        dst.is_repacked_q8 = true;

        var cmd = try metal_command.beginCommand(self.device.ctx);
        dispatchCopyU32OnCmd(self, &cmd, &staging, &dst, @intCast(size_bytes / @sizeOf(u32)), 0, 0);
        cmd.commitAndWait();
        return dst;
    }

    /// Initialize the Metal inference engine, allocating GPU buffers and compiling pipelines.
    pub fn init(
        model: *const metal_loader.Model,
        device: *const metal_device.MetalDevice,
        allocator: std.mem.Allocator,
        options: InitOptions,
    ) !InferenceEngine {
        const cfg = model.config;
        const ctx = device.ctx;
        const weights_bytes = tensorBytes(model);
        const runtime_profile = memory_plan.profile(cfg);
        const requested_ctx = memory_plan.requestedContextTokens(cfg, null, runtime_context_cap);
        const max_ctx = runtime_profile.maxContextTokensForUnifiedBudget(
            weights_bytes,
            memoryPlanningBudget(device),
            requested_ctx,
        );
        if (max_ctx == 0) {
            log.err("No decode context fits within {d:.2} GiB Metal planning budget ({d:.2} GiB reported working set)", .{
                @as(f64, @floatFromInt(memoryPlanningBudget(device))) / (1024.0 * 1024.0 * 1024.0),
                @as(f64, @floatFromInt(memoryBudget(device))) / (1024.0 * 1024.0 * 1024.0),
            });
            return error.ContextLengthDoesNotFit;
        }
        if (max_ctx < requested_ctx) {
            log.warn("Metal context trimmed from {d} to {d} tokens to fit current UMA budget", .{
                requested_ctx,
                max_ctx,
            });
        } else {
            log.info("Metal KV cache planned context: requested {d}, reserved {d}", .{
                requested_ctx,
                max_ctx,
            });
        }

        // Compute dimension-dependent sizes
        const q_dim: u32 = cfg.n_heads * cfg.head_dim;
        const kv_dim: u32 = kvDim(cfg);
        const inter_dim: u32 = if (cfg.intermediate_dim > 0) cfg.intermediate_dim else cfg.hidden_dim * 4;
        const shexp_inter_dim: u32 = if (cfg.shared_expert_intermediate_dim > 0) cfg.shared_expert_intermediate_dim else inter_dim;
        const d_inner: u32 = cfg.ssm_d_inner;
        const conv_channels: u32 = if (d_inner > 0) d_inner + 2 * cfg.ssm_n_group * cfg.ssm_d_state else 0;
        const kv_cache_q8 = options.kv_cache_q8_override orelse
            readBoolEnv("ZINC_METAL_KV_Q8") orelse
            defaultKvCacheQ8Enabled(cfg, options.debug_validation_enabled);
        const kv_cache_bytes_per_token: usize = @intCast(kvCacheBytesPerToken(cfg, kv_cache_q8));
        const kv_cache_head_stride_bytes: u32 = if (kv_cache_q8)
            @intCast(@divTrunc(cfg.head_dim, 32) * 34)
        else
            cfg.head_dim * @sizeOf(f32);

        // Buffer sizes (max across all uses)
        const hidden_size: usize = @as(usize, cfg.hidden_dim) * @sizeOf(f32);
        const q_gate_size: usize = @as(usize, q_dim) * 2 * @sizeOf(f32);
        const attn_out_size: usize = @max(q_gate_size, @as(usize, conv_channels) * @sizeOf(f32));
        const head_total: usize = @as(usize, q_dim) * @sizeOf(f32);
        const kv_total: usize = @as(usize, kv_dim) * @sizeOf(f32);
        const gate_size: usize = @max(@max(head_total, @as(usize, inter_dim) * @sizeOf(f32)), @as(usize, d_inner) * @sizeOf(f32));
        const up_size: usize = @max(@as(usize, inter_dim) * @sizeOf(f32), @as(usize, shexp_inter_dim) * @sizeOf(f32));
        const swiglu_size: usize = @max(up_size, @as(usize, conv_channels) * @sizeOf(f32));
        const vocab_size: usize = @as(usize, cfg.vocab_size) * @sizeOf(f32);
        const kv_cache_size: usize = @as(usize, max_ctx) * kv_cache_bytes_per_token;
        const page_table_size: usize = @as(usize, max_ctx) * @sizeOf(u32);
        const router_size: usize = @max(@as(usize, cfg.n_experts), @as(usize, if (cfg.ssm_dt_rank > 0) cfg.ssm_dt_rank else 1)) * @sizeOf(f32);
        const router_output_size: usize = @max(@as(usize, cfg.n_experts_used) * 2 * @sizeOf(u32), 8);
        const expert_ids_size: usize = @max(@as(usize, cfg.n_experts_used) * @sizeOf(u32), 4);
        const expert_inter_batch_size: usize = @max(@as(usize, cfg.n_experts_used) * @as(usize, inter_dim) * @sizeOf(f32), 4);
        const expert_hidden_batch_size: usize = @max(@as(usize, cfg.n_experts_used) * @as(usize, cfg.hidden_dim) * @sizeOf(f32), 4);

        // Allocate intermediate buffers
        var self: InferenceEngine = undefined;
        self.model = model;
        self.device = device;
        self.config = cfg;
        self.allocator = allocator;
        self.position = 0;
        self.max_context_tokens = max_ctx;
        self.profile_enabled = options.profile_enabled;
        self.debug_validation_enabled = options.debug_validation_enabled;
        self.gemma_moe_validation_enabled = readBoolEnv("ZINC_GEMMA_MOE_VALIDATE") orelse false;
        self.qwen_prefill_validation_enabled =
            (readBoolEnv("ZINC_QWEN36_35B_PREFILL_VALIDATE") orelse false) or
            (readBoolEnv("ZINC_QWEN36_PREFILL_VALIDATE") orelse false);
        self.in_prefill_phase = false;
        self.qwen_ssm_prefill_proj_enabled =
            readBoolEnv("ZINC_QWEN36_35B_SSM_PREFILL_PROJ") orelse
            readBoolEnv("ZINC_QWEN36_SSM_PREFILL_PROJ") orelse
            defaultQwen36SsmPrefillProjectionEnabled(cfg);
        self.qwen_ssm_proj_validate_layer =
            readU32Env("ZINC_QWEN36_35B_SSM_PROJ_VALIDATE_LAYER") orelse
            readU32Env("ZINC_QWEN36_SSM_PROJ_VALIDATE_LAYER") orelse
            readU32Env("ZINC_QWEN36_35B_PREFILL_VALIDATE_LAYER") orelse
            readU32Env("ZINC_QWEN36_PREFILL_VALIDATE_LAYER") orelse
            0;
        self.fused_ssm_norm_enabled = readBoolEnv("ZINC_METAL_FUSED_SSM_NORM") orelse defaultFusedSsmNormEnabled(cfg);
        self.fused_ssm_delta_gated_norm_enabled =
            readBoolEnv("ZINC_METAL_FUSED_SSM_DELTA_GATED_NORM") orelse
            defaultQwen36SsmPrefillProjectionEnabled(cfg);
        self.qwen_ssm_delta_gated_norm_exact_enabled =
            readBoolEnv("ZINC_METAL_QWEN_SSM_DELTA_GATED_NORM_EXACT") orelse
            defaultQwen36SsmPrefillProjectionEnabled(cfg);
        self.private_decode_buffers = if (options.debug_validation_enabled or
            self.gemma_moe_validation_enabled or
            self.qwen_prefill_validation_enabled)
            false
        else
            options.private_decode_buffers_override orelse
                readBoolEnv("ZINC_METAL_PRIVATE_DECODE") orelse
                modelSupportsPrivateDecodeBuffers(model, cfg);
        self.command_encoder_mode = options.command_encoder_mode orelse defaultCommandEncoderMode(cfg);
        self.kv_cache_q8 = kv_cache_q8;
        self.kv_cache_head_stride_bytes = kv_cache_head_stride_bytes;
        self.kv_cache_bytes_per_token = @intCast(kv_cache_bytes_per_token);
        self.q8_tg_override = null;
        self.q8_dual_tg_override = null;
        self.q8_tg_size_env_present = std.posix.getenv("ZINC_METAL_Q8_TG_SIZE") != null;
        self.qwen_shared_down_q8_quad_enabled = readBoolEnv("ZINC_METAL_QWEN_SHARED_DOWN_Q8_QUAD") orelse true;
        self.qwen_ssm_q8_quad_enabled = readBoolEnv("ZINC_METAL_QWEN_SSM_Q8_QUAD") orelse true;
        self.qwen_ssm_out_q8_k4096_enabled = readBoolEnv("ZINC_METAL_QWEN_SSM_OUT_Q8_K4096") orelse true;
        self.qwen_attn_q8_k2048_quad_enabled = readBoolEnv("ZINC_METAL_QWEN_ATTN_Q8_K2048_QUAD") orelse true;
        self.qwen_attn_out_q8_k4096_enabled = readBoolEnv("ZINC_METAL_QWEN_ATTN_OUT_Q8_K4096") orelse true;
        self.qwen_ssm_q8_tg128_enabled = readBoolEnv("ZINC_METAL_QWEN_SSM_Q8_TG128") orelse true;
        self.qwen_ssm_repacked_q8_quad_enabled = readBoolEnv("ZINC_METAL_QWEN_SSM_REPACKED_Q8_QUAD") orelse true;
        self.qwen_q5k_down_k512_quad_enabled = readBoolEnv("ZINC_METAL_QWEN_Q5K_DOWN_K512_QUAD") orelse true;
        self.qwen_q5k_down_k512_tri_enabled = readBoolEnv("ZINC_METAL_QWEN_Q5K_DOWN_K512_TRI") orelse true;
        self.qwen_f32_gate_acc_qwen2048_enabled = readBoolEnv("ZINC_METAL_QWEN_F32_GATE_ACC_QWEN2048") orelse true;
        self.qwen_moe_acc_next_norm_enabled = readBoolEnv("ZINC_METAL_QWEN_MOE_ACC_NEXT_NORM") orelse true;
        self.qwen_moe_acc_seed_next_norm_enabled = readBoolEnv("ZINC_METAL_QWEN_MOE_ACC_SEED_NEXT_NORM") orelse true;
        self.qwen_moe_acc_shared_gate_f32_ready = false;
        self.qwen_moe_acc_shared_gate_f32_qwen2048_ready = false;
        self.qwen_moe_acc_next_norm_ready = false;
        self.qwen_moe_acc_seed_next_norm_ready = false;
        self.qwen_moe_acc_scalar_ready = false;
        self.qwen_moe_acc_scalar_seed_next_norm_ready = false;
        self.qwen_residual_router_q8_fused_enabled = readBoolEnv("ZINC_METAL_QWEN_RESIDUAL_ROUTER_Q8_FUSED") orelse true;
        self.qwen_residual_router_f32_fused_enabled = readBoolEnv("ZINC_METAL_QWEN_RESIDUAL_ROUTER_F32_FUSED") orelse true;
        self.qwen_final_tail_kv_fused_norm_enabled = readBoolEnv("ZINC_METAL_QWEN_FINAL_TAIL_KV_FUSED_NORM") orelse true;
        self.qwen_layer0_shared_down_prefill_enabled = readBoolEnv("ZINC_METAL_QWEN_LAYER0_SHARED_DOWN_PREFILL") orelse true;
        self.qwen_layer0_shared_gate_prefill_enabled = readBoolEnv("ZINC_METAL_QWEN_LAYER0_SHARED_GATE_PREFILL") orelse true;
        // Per-kernel timing probe — default off, distorts decode tok/s when on
        // (each dispatch becomes a commit+wait+restart sync). The cycle-33 auto-
        // enable on `--profile` runs was reverted: the probe's per-dispatch
        // commits bypass the normal `commitAndWait` accounting and zero-fill the
        // `barriers/step`, `gpu-moe barriers/request`, and `wait:` totals in the
        // profile output, making `--profile` 6× slower AND eliminating the
        // structural evidence (barrier counts per phase) the loop relies on for
        // next-cycle direction. The agent then optimized against zero'd profile
        // counters for ~45 cycles before self-diagnosing it. Per-kernel µs
        // evidence is still available via `ZINC_METAL_KERNEL_TIMING=1` for an
        // explicit out-of-band pass.
        if (readBoolEnv("ZINC_METAL_KERNEL_TIMING") orelse false) {
            kernel_timing.enable();
        }
        self.request_profile = .{};
        self.prefill_profile = .{};
        self.qwen_ssm_proj_validate_captured_tokens = 0;
        self.qwen_ssm_prefill_proj_active_tokens = 0;
        self.qwen_ssm_prefill_branch_active_tokens = 0;
        self.qwen_ssm_prefill_branch_norm_active_tokens = 0;
        self.qwen_ssm_prefill_shared_down_active_tokens = 0;
        self.qwen_ssm_prefill_shared_gate_active_tokens = 0;
        self.qwen_ssm_prefill_router_active_tokens = 0;
        self.qwen_ssm_proj_validate_norm_buf = .{ .handle = null, .size = 0, .cpu_ptr = null, .is_mmap_wrapped = false };
        self.qwen_ssm_proj_validate_qkv_ref_buf = .{ .handle = null, .size = 0, .cpu_ptr = null, .is_mmap_wrapped = false };
        self.qwen_ssm_proj_validate_z_ref_buf = .{ .handle = null, .size = 0, .cpu_ptr = null, .is_mmap_wrapped = false };
        self.qwen_ssm_proj_validate_alpha_ref_buf = .{ .handle = null, .size = 0, .cpu_ptr = null, .is_mmap_wrapped = false };
        self.qwen_ssm_proj_validate_beta_ref_buf = .{ .handle = null, .size = 0, .cpu_ptr = null, .is_mmap_wrapped = false };
        self.qwen_moe_route_validate_captured_tokens = 0;
        self.qwen_moe_route_validate_target_tokens = 0;
        self.qwen_moe_route_validate_failure_hint_emitted = false;
        self.qwen_moe_route_validate_layer_input_ref_buf = .{ .handle = null, .size = 0, .cpu_ptr = null, .is_mmap_wrapped = false };
        self.qwen_moe_route_validate_norm_buf = .{ .handle = null, .size = 0, .cpu_ptr = null, .is_mmap_wrapped = false };
        self.qwen_moe_route_validate_routing_buf = .{ .handle = null, .size = 0, .cpu_ptr = null, .is_mmap_wrapped = false };
