        self.dmmv_q8_0_k512_quad_unpacked_pipe = try loadShaderPipeline(ctx, "dmmv_q8_0_k512_quad_unpacked");
        self.dmmv_q8_0_quad_pipe = try loadShaderPipeline(ctx, "dmmv_q8_0_quad");
