) bool {
    return engine.qwen_residual_router_q8_fused_enabled and
        !engine.debug_validation_enabled and
        !engine.gemma_moe_validation_enabled and
        !engine.qwen_prefill_validation_enabled and
        engine.config.architecture == .qwen2_moe and
        engine.config.ssm_d_inner == 4096 and
        hidden_dim == 2048 and
        n_experts == 256 and
        k <= 16 and
        residual_offset == 0 and
        router.info.type_ == .q8_0 and
        engine.residual_rms_norm_router_q8_0_topk_pipe.handle != null and
        engine.residual_rms_norm_router_q8_0_topk_pipe.thread_execution_width == 32 and
        engine.residual_rms_norm_router_q8_0_topk_pipe.max_threads_per_threadgroup >= 1024;
}

fn canUseQwenRouterQ8K2048Exact(
    engine: *const InferenceEngine,
    router: *const metal_loader.LoadedTensor,
    hidden_dim: u32,
    n_experts: u32,
    k: u32,
) bool {
    return engine.config.architecture == .qwen2_moe and
        engine.config.ssm_d_inner == 4096 and
        hidden_dim == 2048 and
        n_experts == 256 and
        k == 8 and
        router.info.type_ == .q8_0;
}

const RouterWeightRef = struct {
    buffer: *const MetalBuffer,
    offset: u32,
};

fn routerWeightRef(engine: *const InferenceEngine, layer_idx: usize, router: *const metal_loader.LoadedTensor) RouterWeightRef {
    if (engine.private_router_bufs) |bufs| {
        if (layer_idx < bufs.len and bufs[layer_idx].handle != null) {
            return .{ .buffer = &bufs[layer_idx], .offset = 0 };
        }
    }
    return .{ .buffer = &router.gpu_buffer, .offset = tensorPageOffset(engine.model, router) };
}

fn dispatchQwenResidualRmsNormRouterQ8TopkOnCmd(
    engine: *InferenceEngine,
    cmd: *MetalCommand,
    hidden: *const MetalBuffer,
    residual: *const MetalBuffer,
    norm_out: *const MetalBuffer,
    norm_weight: *const MetalBuffer,
    router: *const metal_loader.LoadedTensor,
    router_buf: *const MetalBuffer,
    router_offset: u32,
    output: *const MetalBuffer,
    hidden_dim: u32,
    n_experts: u32,
    k: u32,
    scale: f32,
    residual_offset: u32,
) void {
    recordDmmvProfile(engine, router, n_experts, hidden_dim);
    if (engine.profile_enabled) engine.request_profile.router_topk_calls += 1;
    const push = ResidualRmsNormRouterQ8TopkPush{
        .n = hidden_dim,
        .eps = engine.config.rms_norm_eps,
        .scale = scale,
        .residual_offset = residual_offset,
        .n_experts = n_experts,
        .K = hidden_dim,
        .k = k,
        .a_offset = router_offset,
    };
    const bufs = [_]*const MetalBuffer{ hidden, residual, norm_out, norm_weight, router_buf, output };
    if (router_buf.is_repacked_q8 and
        canUseQwenRouterQ8K2048Exact(engine, router, hidden_dim, n_experts, k) and
        engine.residual_rms_norm_router_q8_0_topk_repacked_k2048_pipe.handle != null and
        engine.residual_rms_norm_router_q8_0_topk_repacked_k2048_pipe.thread_execution_width == 32 and
        engine.residual_rms_norm_router_q8_0_topk_repacked_k2048_pipe.max_threads_per_threadgroup >= 1024)
    {
        cmd.dispatchV2(&engine.residual_rms_norm_router_q8_0_topk_repacked_k2048_pipe, .{ 1, 1, 1 }, .{ 1024, 1, 1 }, &bufs, &push, @sizeOf(ResidualRmsNormRouterQ8TopkPush), 0);
        return;
    }
    if (canUseQwenRouterQ8K2048Exact(engine, router, hidden_dim, n_experts, k) and
        engine.residual_rms_norm_router_q8_0_topk_k2048_pipe.handle != null and
        engine.residual_rms_norm_router_q8_0_topk_k2048_pipe.thread_execution_width == 32 and
        engine.residual_rms_norm_router_q8_0_topk_k2048_pipe.max_threads_per_threadgroup >= 1024)
    {
        cmd.dispatchV2(&engine.residual_rms_norm_router_q8_0_topk_k2048_pipe, .{ 1, 1, 1 }, .{ 1024, 1, 1 }, &bufs, &push, @sizeOf(ResidualRmsNormRouterQ8TopkPush), 0);
        return;
    }
    cmd.dispatchV2(&engine.residual_rms_norm_router_q8_0_topk_pipe, .{ 1, 1, 1 }, .{ 1024, 1, 1 }, &bufs, &push, @sizeOf(ResidualRmsNormRouterQ8TopkPush), 0);
}

fn canUseQwenResidualRmsNormRouterF32Topk(
    engine: *const InferenceEngine,
    router: *const metal_loader.LoadedTensor,
    shared_gate: ?*const metal_loader.LoadedTensor,
    hidden_dim: u32,
    n_experts: u32,
    k: u32,
) bool {
    const gate = shared_gate orelse return false;
    return engine.qwen_residual_router_f32_fused_enabled and
        !engine.debug_validation_enabled and
        !engine.gemma_moe_validation_enabled and
        !engine.qwen_prefill_validation_enabled and
        engine.config.architecture == .qwen2_moe and
        engine.config.ssm_d_inner == 4096 and
        hidden_dim == 2048 and
        n_experts == 256 and
        k == 8 and
        router.info.type_ == .f32 and
        gate.info.type_ == .f32 and
        gate.info.numElements() == hidden_dim and
        engine.residual_rms_norm_router_f32_topk_pipe.handle != null and
        engine.residual_rms_norm_router_f32_topk_pipe.thread_execution_width == 32 and
        // Cycle-42: kernel now uses TG_SIZE=1024 (matches the Q8 router sibling).
        engine.residual_rms_norm_router_f32_topk_pipe.max_threads_per_threadgroup >= 1024;
}

fn dispatchQwenResidualRmsNormRouterF32TopkOnCmd(
    engine: *InferenceEngine,
    cmd: *MetalCommand,
    hidden: *const MetalBuffer,
    residual: *const MetalBuffer,
    norm_out: *const MetalBuffer,
    norm_weight: *const MetalBuffer,
    router: *const metal_loader.LoadedTensor,
    output: *const MetalBuffer,
    shared_gate: *const metal_loader.LoadedTensor,
    shared_gate_output: *const MetalBuffer,
    hidden_dim: u32,
    n_experts: u32,
    k: u32,
    scale: f32,
    residual_offset: u32,
) void {
    recordDmmvProfile(engine, router, n_experts, hidden_dim);
    recordDmmvProfile(engine, shared_gate, 1, hidden_dim);
    if (engine.profile_enabled) engine.request_profile.router_topk_calls += 1;
    const push = ResidualRmsNormRouterF32TopkPush{
        .n = hidden_dim,
        .eps = engine.config.rms_norm_eps,
        .scale = scale,
        .residual_offset = residual_offset,
        .n_experts = n_experts,
        .K = hidden_dim,
        .k = k,
        .a_offset = tensorPageOffset(engine.model, router),
        .shared_gate_offset = tensorPageOffset(engine.model, shared_gate),
    };
    const bufs = [_]*const MetalBuffer{ hidden, residual, norm_out, norm_weight, &router.gpu_buffer, output, &shared_gate.gpu_buffer, shared_gate_output };
    // Cycle-42: TG_SIZE 512→1024 to widen simdgroup count from 16 to 32 in the
    // single-TG dispatch — the 256-expert router GEMM now runs 4 row_blocks
    // instead of 8, halving per-simdgroup work on the hottest timed kernel.
    //
    // Cycle 77 (analysis-only, NO production change): cycles 62-76 have plateaued
    // on simd_sum packing variants of this and sibling kernels (decode tok/s
    // 80.4–80.8, all within the noise band, kept for completeness). Smallest-
    // named-bucket hypothesis from profile timing (1436 calls × ~37 us true =
    // 53 ms/request true ≈ 17% of true decode time, after stripping the ~6.4×
    // ZINC_METAL_KERNEL_TIMING distortion): this dispatch is single-core-bound
    // on a 40-core GPU. Grid `.{1,1,1}` × block `.{1024,1,1}` = 32 simdgroups,
    // which fully saturates ONE Apple9 core's simdgroup capacity but leaves
    // the other 39 cores idle for the kernel's ~37 us. Cycle 42 already pushed
    // simdgroups per TG to the per-core maximum, so further TG_SIZE/SIMD-pack
    // retunes cannot escape the single-core ceiling. The remaining decode
    // headroom on this kernel requires CROSS-CORE parallelism, not intra-TG
    // tuning. Concrete next-cycle moves (each non-retune):
    //   A. Split the router GEMM into N>1 TGs (e.g. 4 TGs × 64 experts each)
    //      with a second `topk_reduce_shared_gate` dispatch that reads partial
    //      expert scores from a small global buffer and produces the topk +
    //      shared-gate scalar. Trades one dispatch+barrier per layer for 4×
    //      cross-core parallelism on the router GEMM phase (~3-4 ms/req decode).
    //   B. Keep the fusion but use `.{4,1,1}` grid where row 0 owns Phase 1+2
    //      (residual+RMSNorm) and rows 1-3 own disjoint slices of Phase 3
    //      (router GEMM). Requires inter-TG barrier (Metal `simdgroup_event`
    //      or fence) which Apple9 supports but adds complexity.
    //   C. Unfuse the router GEMM entirely, run as `dispatchGemmF32SmallOnCmd`
    //      (forward_metal.zig:2686) which is already a multi-TG kernel, then
    //      run a small `residual_rms_norm_topk_shared_gate.metal` fusion that
    //      consumes precomputed router scores. Simplest impl, biggest dispatch
    //      cost (+1 dispatch per layer × 40 layers = ~40 us overhead/token vs
    //      a potential ~4 ms saving per token from 4× core utilization).
    // Each requires writing/testing a new kernel; the per-call true time is
    // 37 us (≈1500 us decode if naively 4× faster on this kernel ⇒ ~12% upside
    // if all overhead absorbed). Recorded here so the next cycle can pick a
    // path instead of repeating the simd_sum-pack plateau.
    cmd.dispatchV2(&engine.residual_rms_norm_router_f32_topk_pipe, .{ 1, 1, 1 }, .{ 1024, 1, 1 }, &bufs, &push, @sizeOf(ResidualRmsNormRouterF32TopkPush), 0);
}

/// Triple-fused: residual_norm + residual_add + output_norm.
///   residual_normed[i] = residual_w[i] * residual[i] * rsqrt(mean(residual^2))
///   hidden[i]         += residual_normed[i]
///   norm_out[i]        = output_w[i]   * hidden[i]   * rsqrt(mean(hidden^2))
/// Replaces (post_*_norm in-place) + barrier + (residual_rms_norm) with a
/// single dispatch on the dense-FFN/next-attn boundary.
/// post_norm_residual_rms_norm.metal: buffer(0)=push, (1)=hidden,
/// (2)=residual, (3)=residual_w, (4)=norm_out, (5)=output_w.
fn dispatchPostNormResidualRmsNormOnCmd(
    engine: *InferenceEngine,
    cmd: *MetalCommand,
    hidden: *const MetalBuffer,
    residual: *const MetalBuffer,
    residual_w: *const MetalBuffer,
    norm_out: *const MetalBuffer,
    output_w: *const MetalBuffer,
    n: u32,
    hidden_scale: f32,
) void {
    const push = PostNormResidualRmsNormPush{
        .n = n,
        .eps = engine.config.rms_norm_eps,
        .hidden_scale = hidden_scale,
    };
    const bufs = [_]*const MetalBuffer{ hidden, residual, residual_w, norm_out, output_w };
    cmd.dispatchV2(&engine.post_norm_residual_rms_norm_pipe, .{ 1, 1, 1 }, .{ 256, 1, 1 }, &bufs, &push, @sizeOf(PostNormResidualRmsNormPush), 0);
}

fn canUseQwenPostNormResidualRouterF32SharedGate(
    engine: *const InferenceEngine,
    router: *const metal_loader.LoadedTensor,
    shared_gate: ?*const metal_loader.LoadedTensor,
    hidden_dim: u32,
    n_experts: u32,
    k: u32,
) bool {
    const gate = shared_gate orelse return false;
    return !engine.debug_validation_enabled and
        !engine.gemma_moe_validation_enabled and
        !engine.qwen_prefill_validation_enabled and
        engine.config.architecture == .qwen2_moe and
        engine.config.ssm_d_inner == 4096 and
        hidden_dim == 2048 and
        n_experts == 256 and
        k == 8 and
        router.info.type_ == .f32 and
        gate.info.type_ == .f32 and
        gate.info.numElements() == hidden_dim and
        engine.post_norm_residual_router_f32_shared_gate_pipe.handle != null and
        engine.post_norm_residual_router_f32_shared_gate_pipe.thread_execution_width == 32 and
        engine.post_norm_residual_router_f32_shared_gate_pipe.max_threads_per_threadgroup >= 1024;
}

fn dispatchQwenPostNormResidualRouterF32SharedGateOnCmd(
    engine: *InferenceEngine,
    cmd: *MetalCommand,
    hidden: *const MetalBuffer,
    residual: *const MetalBuffer,
    post_norm_weight: *const MetalBuffer,
    norm_out: *const MetalBuffer,
    ffn_norm_weight: *const MetalBuffer,
    router: *const metal_loader.LoadedTensor,
    router_output: *const MetalBuffer,
    shared_gate: *const metal_loader.LoadedTensor,
    shared_gate_output: *const MetalBuffer,
    hidden_dim: u32,
    n_experts: u32,
    k: u32,
) void {
    recordDmmvProfile(engine, router, n_experts, hidden_dim);
    recordDmmvProfile(engine, shared_gate, 1, hidden_dim);
    if (engine.profile_enabled) engine.request_profile.router_topk_calls += 1;
    const push = PostNormResidualRouterF32SharedGatePush{
        .n = hidden_dim,
        .eps = engine.config.rms_norm_eps,
        .n_experts = n_experts,
        .K = hidden_dim,
        .k = k,
        .router_offset = tensorPageOffset(engine.model, router),
        .shared_gate_offset = tensorPageOffset(engine.model, shared_gate),
        .output_stride = k * 2,
    };
    const bufs = [_]*const MetalBuffer{
        &router.gpu_buffer,
        hidden,
        residual,
        post_norm_weight,
        norm_out,
        ffn_norm_weight,
        router_output,
        &shared_gate.gpu_buffer,
        shared_gate_output,
    };
    cmd.dispatchV2(&engine.post_norm_residual_router_f32_shared_gate_pipe, .{ 1, 1, 1 }, .{ 1024, 1, 1 }, &bufs, &push, @sizeOf(PostNormResidualRouterF32SharedGatePush), 1);
}

/// Dispatch a Q4_K × f32 batched matmul.
///
/// Computes `output[N×M] = weight[M×K] × input[N×K]` where weight rows are
/// stored in Q4_K blocks (144 bytes / 256 elements). Use for prefill when
/// N ≥ ~16 — below that DMMV is faster.
/// gemm_q4k.metal: buffer(0)=push, buffer(1)=weights, buffer(2)=input, buffer(3)=output.
fn dispatchGemmQ4KOnCmd(
    engine: *InferenceEngine,
    cmd: *MetalCommand,
    weight: *const metal_loader.LoadedTensor,
    input: *const MetalBuffer,
    output: *const MetalBuffer,
    M: u32,
    K: u32,
    N: u32,
) void {
    std.debug.assert(K % 256 == 0);
    const push = GemmPush{
        .ne00 = @intCast(K),
        .ne02 = 1,
        .nb01 = @as(u64, K / 256) * 144,
        .nb02 = 0,
        .ne12 = 1,
        .nb10 = 4,
        .nb11 = @as(u64, K) * 4,
        .nb12 = 0,
        .ne0 = @intCast(M),
        .ne1 = @intCast(N),
        .src0_off = tensorPageOffset(engine.model, weight),
    };
    const bufs = [_]*const MetalBuffer{ &weight.gpu_buffer, input, output };
    const grid = [_]u32{ (N + 31) / 32, (M + 63) / 64, 1 };
    cmd.dispatchV2WithTgMem(&engine.gemm_q4k_pipe, grid, .{ 128, 1, 1 }, &bufs, &push, @sizeOf(GemmPush), 0, 8192);
}

/// Dispatch a Q5_K × f32 batched matmul. Same llama.cpp simdgroup-MM tile
/// shape as Q4_K/Q6_K, with Q5_K's 176-byte blocks.
fn dispatchGemmQ5KOnCmd(
    engine: *InferenceEngine,
    cmd: *MetalCommand,
    weight: *const metal_loader.LoadedTensor,
    input: *const MetalBuffer,
    output: *const MetalBuffer,
