    ssm_a_ptr[0] = 0.5;
    ssm_a_ptr[1] = -0.75;
    beta_ptr[0] = 0.25;
    beta_ptr[1] = -0.5;
    for (0..state_len) |i| {
        state_ptr[i] = @as(f32, @floatFromInt(@as(i32, @intCast(i % 7)) - 3)) * 0.1;
    }
    @memset(output_ptr[0..d_inner], 0);

    var ref_state: [32]f32 = undefined;
    var ref_output: [8]f32 = [_]f32{0} ** 8;
    @memcpy(ref_state[0..state_len], state_ptr[0..state_len]);
