        conv_ptr[0..conv_len],
        alpha_ptr[0..dt_rank],
        dt_bias_ptr[0..dt_rank],
        beta_ptr[0..dt_rank],
        ssm_a_ptr[0..dt_rank],
        ref_state[0..state_len],
        ref_output[0..d_inner],
        dt_rank,
        head_v_dim,
        d_state,
        n_group,
    );

    const push = SsmDeltaNetPush{
        .d_inner = d_inner,
        .dt_rank = dt_rank,
        .head_v_dim = head_v_dim,
        .d_state = d_state,
        .n_group = n_group,
        .ssm_a_is_f16 = 0,
        .dt_bias_is_f16 = 0,
        .has_dt_bias = 1,
        .has_ssm_a = 1,
        .alpha_offset = 0,
        .beta_offset = 0,
        .output_offset = 0,
    };
    const bufs = [_]*const MetalBuffer{
        &conv_buf,
        &alpha_buf,
        &dt_bias_buf,
        &ssm_a_buf,
        &beta_buf,
        &state_buf,
        &output_buf,
    };

    var cmd = try metal_command.beginCommand(ctx);
    cmd.dispatchV2(&pipe, .{ dt_rank, 1, 1 }, .{ 64, 1, 1 }, &bufs, &push, @sizeOf(SsmDeltaNetPush), 0);
    cmd.commitAndWait();

    for (0..d_inner) |i| {
        try std.testing.expectApproxEqAbs(ref_output[i], output_ptr[i], 0.0005);
    }
    for (0..state_len) |i| {
        try std.testing.expectApproxEqAbs(ref_state[i], state_ptr[i], 0.0005);
    }
}

