    refRunSsmDeltaNet(
        conv_ptr[0..conv_len],
        alpha_ptr[0..dt_rank],
        dt_bias_ptr[0..dt_rank],
        beta_ptr[0..dt_rank],
        ssm_a_ptr[0..dt_rank],
        ref_state[0..state_len],
        ref_output[0..d_inner],
        dt_rank,
        head_v_dim,
        d_state,
        n_group,
    );

    const push = SsmDeltaNetPush{
        .d_inner = @intCast(d_inner),
        .dt_rank = @intCast(dt_rank),
        .head_v_dim = @intCast(head_v_dim),
        .d_state = @intCast(d_state),
