        .has_dt_bias = 1,
        .has_ssm_a = 1,
        .alpha_offset = 0,
        .beta_offset = 0,
        .output_offset = 0,
    };
    const bufs = [_]*const MetalBuffer{
        &conv_buf,
        &alpha_buf,
        &dt_bias_buf,
        &ssm_a_buf,
        &beta_buf,
        &state_buf,
        &output_buf,
    };

    var cmd = try metal_command.beginCommand(ctx);
    cmd.dispatchV2(&pipe, .{ @intCast(dt_rank), 1, 1 }, .{ 64, 1, 1 }, &bufs, &push, @sizeOf(SsmDeltaNetPush), 0);
    cmd.commitAndWait();

    for (0..d_inner) |i| {
