    @memset(weight_buf.cpu_ptr.?[0..weight_buf.size], 0);
    @memset(input_buf.cpu_ptr.?[0..input_buf.size], 0);
    @memset(output_buf.cpu_ptr.?[0..output_buf.size], 0);

