    cmd.commitAndWait();

    var expected = [_]f32{
        1.0, 1.0, 1.0, 1.0,
        2.0, 2.0, 2.0, 2.0,
    };
    for (0..n_tokens) |token| {
        const row = token * routing_stride;
        for (0..k) |slot| {
            const expert = routing_ptr[row + slot];
            const route = token * k + slot;
            const weight: f32 = @bitCast(routing_ptr[row + k + slot]);
            for (0..hidden_dim) |dim| {
