    defer metal_buffer.freeBuffer(&src_v);
    var dst_k = try metal_buffer.createBuffer(ctx, 16 * @sizeOf(f32));
    defer metal_buffer.freeBuffer(&dst_k);
    var dst_v = try metal_buffer.createBuffer(ctx, 16 * @sizeOf(f32));
