    if (pipe.max_threads_per_threadgroup < 1024) return error.SkipZigTest;

    const n: u32 = 2048;
    const n_used: u32 = 8;
    const n_usize: usize = @intCast(n);
    const n_used_usize: usize = @intCast(n_used);

